import React, { useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../App';

const Logo = () => (
  <svg width="28" height="28" viewBox="0 0 48 48" fill="none">
    <path d="M24 3L5 11.5V23C5 34.5 13.2 43.5 24 45.5C34.8 43.5 43 34.5 43 23V11.5L24 3Z" fill="#16a34a" opacity="0.15" stroke="#16a34a" strokeWidth="2"/>
    <rect x="21.5" y="13" width="5" height="22" rx="2.5" fill="#16a34a"/>
    <rect x="13" y="21.5" width="22" height="5" rx="2.5" fill="#16a34a"/>
  </svg>
);

export default function Navbar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [open, setOpen] = useState(false);

  const handleLogout = () => { logout(); navigate('/'); setOpen(false); };
  const isActive = p => location.pathname.startsWith(p);

  return (
    <nav style={{ background: 'rgba(255,255,255,0.97)', backdropFilter: 'blur(12px)', borderBottom: '1px solid #e5e7eb', position: 'sticky', top: 0, zIndex: 100, height: 64 }}>
      <div style={{ maxWidth: 1100, margin: '0 auto', padding: '0 1.25rem', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        <Link to="/" style={{ display: 'flex', alignItems: 'center', gap: 8, textDecoration: 'none' }}>
          <Logo />
          <span style={{ fontFamily: 'Fraunces, serif', fontWeight: 700, fontSize: '1.2rem', color: '#111827' }}>MediHelp</span>
        </Link>

        {/* Desktop */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }} className="desktop-nav">
          {!user ? (
            <>
              <Link to="/" style={{ color: isActive('/') && location.pathname === '/' ? '#16a34a' : '#6b7280', fontWeight: 500, fontSize: '0.9rem', padding: '0.4rem 0.75rem', borderRadius: 8, textDecoration: 'none' }}>Home</Link>
              <Link to="/login" className="btn btn-outline btn-sm">Sign In</Link>
              <Link to="/register" className="btn btn-primary btn-sm">Get Started</Link>
            </>
          ) : (
            <>
              <Link to="/dashboard" style={{ color: isActive('/dashboard') ? '#16a34a' : '#6b7280', fontWeight: 500, fontSize: '0.9rem', padding: '0.4rem 0.75rem', borderRadius: 8, textDecoration: 'none' }}>Dashboard</Link>
              {user.role === 'ADMIN' && (
                <Link to="/admin" style={{ color: isActive('/admin') ? '#16a34a' : '#6b7280', fontWeight: 500, fontSize: '0.9rem', padding: '0.4rem 0.75rem', borderRadius: 8, textDecoration: 'none' }}>Admin</Link>
              )}
              <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginLeft: 8, paddingLeft: 8, borderLeft: '1px solid #e5e7eb' }}>
                <div style={{ width: 32, height: 32, borderRadius: '50%', background: 'linear-gradient(135deg, #16a34a, #15803d)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontSize: '0.85rem', fontWeight: 700 }}>
                  {(user.name || 'U')[0].toUpperCase()}
                </div>
                <span style={{ fontSize: '0.875rem', color: '#374151', fontWeight: 500 }}>{user.name?.split(' ')[0]}</span>
                <button onClick={handleLogout} className="btn btn-ghost btn-sm">Logout</button>
              </div>
            </>
          )}
        </div>
      </div>
    </nav>
  );
}
